                      </svg>
                      {t.results.download}
                    </button>
                    <button
                      onClick={() => window.open(thumb.url, '_blank')}
                      className="px-4 bg-slate-50 text-slate-600 hover:bg-slate-100 py-3 rounded-xl transition-colors"
                      title={t.results.open}
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
          <p className="mt-8 text-center text-slate-400 text-sm italic">
            {t.results.notAvailable}
          </p>
        </div>
      )}

      {/* SEO Content / Features */}
      {!metadata && (
        <div className="mt-20">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
