          <span className="text-yellow-400">YT</span>Thumbs
        </h1>
        <p className="text-lg md:text-xl text-slate-600 max-w-2xl mx-auto">
          {t.hero.subtitle}
        </p>
      </div>

      {/* Input Section */}
      <div className="max-w-3xl mx-auto mb-12">
        <div className="flex flex-col md:flex-row gap-3 p-2 bg-white rounded-2xl shadow-xl shadow-slate-200 border border-slate-100 glass-effect">
          <input
            type="text"
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleFetch()}
            placeholder={t.hero.placeholder}
            dir="ltr"
            className={`flex-grow px-6 py-4 rounded-xl text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-green-500 bg-slate-50 transition-all border border-slate-100 ${isRTL ? 'text-right' : 'text-left'}`}
          />
          <button
            onClick={handleFetch}
            disabled={loading}
            className="bg-green-600 hover:bg-green-700 disabled:bg-slate-300 text-white font-bold py-4 px-8 rounded-xl transition-all shadow-lg shadow-green-200 active:scale-95 flex items-center justify-center gap-2"
          >
            {loading ? (
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
