    if (!url.trim()) return;
    setLoading(true);
    setError(null);
    setMetadata(null);

    const videoId = extractVideoId(url);
    if (!videoId) {
      setError(lang === 'en' ? 'Invalid YouTube URL' : 'رابط يوتيوب غير صالح');
      setLoading(false);
      return;
