              <p className="mb-4">Like any other website, YTThumbs uses "cookies". These cookies are used to store information including visitors' preferences, and the pages on the website that the visitor accessed or visited.</p>

              <h4 className="font-bold text-slate-800 mb-2">Google DoubleClick DART Cookie</h4>
              <p className="mb-4">Google is one of a third-party vendor on our site. It also uses cookies, known as DART cookies, to serve ads to our site visitors based upon their visit to other sites on the internet.</p>

              <h4 className="font-bold text-slate-800 mb-2">Our Advertising Partners</h4>
              <p className="mb-4">Some of advertisers on our site may use cookies and web beacons. Our advertising partners are listed below:</p>
              <ul className="list-disc pl-6 mb-4">
                <li>Google: <a href="https://policies.google.com/technologies/ads" className="text-green-600">https://policies.google.com/technologies/ads</a></li>
              </ul>

              <h4 className="font-bold text-slate-800 mb-2">Consent</h4>
              <p className="mb-4">By using our website, you hereby consent to our Privacy Policy and agree to its terms.</p>
            </>
          )}
        </div>
      </div>
    );
  };

  const renderContact = () => (
    <section className="max-w-4xl mx-auto px-4 py-16">
      <h1 className="text-4xl font-bold mb-8 text-slate-900">{t.contact.title}</h1>
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <p className="mb-8 text-slate-600">{t.contact.content}</p>
        <form className="space-y-4" onSubmit={(e) => e.preventDefault()}>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-slate-700">{t.contact.name}</label>
              <input type="text" className="px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-green-500 outline-none" placeholder="John Doe" />
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-sm font-semibold text-slate-700">{t.contact.email}</label>
              <input type="email" className="px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-green-500 outline-none" placeholder="john@example.com" />
            </div>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-semibold text-slate-700">{t.contact.message}</label>
            <textarea rows={4} className="px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-green-500 outline-none" placeholder="Your message here..."></textarea>
          </div>
          <button className="bg-green-600 text-white font-bold py-4 px-8 rounded-xl hover:bg-green-700 transition-colors shadow-lg shadow-green-200">
            {t.contact.send}
          </button>
        </form>
      </div>
    </section>
  );

  return (
    <div className={`min-h-screen bg-pattern flex flex-col`} dir={isRTL ? 'rtl' : 'ltr'}>
      <nav className="sticky top-0 z-50 glass-effect border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20">
            <div className="flex items-center gap-8">
              <div className="flex items-center cursor-pointer group" onClick={handleRefreshHome}>
                <div className="w-10 h-10 mr-3 flex items-center justify-center group-hover:rotate-6 transition-transform overflow-hidden rounded-xl shadow-lg shadow-slate-100">
                   <div className="w-10 h-10 bg-green-500 rounded-xl relative flex items-center justify-center p-1.5 overflow-hidden">
                     <div className="w-full h-full bg-white rounded shadow-inner flex items-center justify-center relative">
                        <svg className="w-6 h-6 text-green-500" fill="currentColor" viewBox="0 0 20 20">
                          <path d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" />
                        </svg>
                        <div className="absolute top-1 right-1 w-2 h-2 bg-yellow-400 rounded-full border border-white"></div>
                     </div>
                     <div className="absolute bottom-0 right-0 w-4 h-4 bg-yellow-400 transform translate-x-1.5 translate-y-1.5 rotate-45 shadow-sm border-t border-l border-white/20"></div>
                   </div>
                </div>
                <span className="text-2xl font-black text-slate-800 tracking-tight">
                  <span className="text-yellow-400">YT</span>Thumbs
                </span>
              </div>
              <div className="hidden lg:flex items-center gap-6">
                <button onClick={handleRefreshHome} className={`font-semibold text-sm transition-colors ${activeTab === 'home' ? 'text-green-600' : 'text-slate-500 hover:text-slate-900'}`}>{t.nav.home}</button>
                <button onClick={() => setActiveTab('about')} className={`font-semibold text-sm transition-colors ${activeTab === 'about' ? 'text-green-600' : 'text-slate-500 hover:text-slate-900'}`}>{t.nav.about}</button>
                <button onClick={() => setActiveTab('faq')} className={`font-semibold text-sm transition-colors ${activeTab === 'faq' ? 'text-green-600' : 'text-slate-500 hover:text-slate-900'}`}>{t.nav.faq}</button>
                <button onClick={() => setActiveTab('blog')} className={`font-semibold text-sm transition-colors ${activeTab === 'blog' ? 'text-green-600' : 'text-slate-500 hover:text-slate-900'}`}>{t.nav.blog}</button>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <LanguageSwitcher current={lang} onChange={setLang} />
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-grow">
        {activeTab === 'home' && renderHome()}
        {activeTab === 'faq' && renderFaqSection(t.faq.title)}
        {activeTab === 'blog' && renderBlog()}
        {activeTab === 'about' && renderSimplePage(t.about.title, t.about.content)}
        {activeTab === 'contact' && renderContact()}
        {activeTab === 'privacy' && renderPrivacyPolicy()}
        {activeTab === 'terms' && renderSimplePage(t.nav.terms, isRTL ? "باستخدامك لموقع YTThumbs، فإنك توافق على سياسة الاستخدام العادل واحترام حقوق منشئي المحتوى الأصليين." : "By using YTThumbs, you agree to follow our Fair Use policy and respect original creators.")}
      </main>

      <footer className="bg-white border-t border-slate-200 pt-16 pb-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center mb-6 cursor-pointer group" onClick={handleRefreshHome}>
                <span className="text-xl font-bold text-slate-800">
                  <span className="text-yellow-400">YT</span>Thumbs
                </span>
              </div>
              <p className="text-slate-500 max-w-sm mb-6 leading-relaxed">
                {t.footer.about}
              </p>
              <p className="text-xs text-slate-400">
                {t.footer.rights}
              </p>
            </div>
            <div>
              <h4 className="font-bold text-slate-800 mb-6 uppercase text-xs tracking-widest">{t.footer.sections.company}</h4>
              <ul className="space-y-4">
                <li><button onClick={() => setActiveTab('about')} className="text-slate-500 hover:text-green-600 text-sm transition-colors">{t.nav.about}</button></li>
                <li><button onClick={() => setActiveTab('contact')} className="text-slate-500 hover:text-green-600 text-sm transition-colors">{t.nav.contact}</button></li>
                <li><button onClick={() => setActiveTab('blog')} className="text-slate-500 hover:text-green-600 text-sm transition-colors">{t.nav.blog}</button></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold text-slate-800 mb-6 uppercase text-xs tracking-widest">{t.footer.sections.legal}</h4>
              <ul className="space-y-4">
                <li><button onClick={() => setActiveTab('privacy')} className="text-slate-500 hover:text-green-600 text-sm transition-colors">{t.nav.privacy}</button></li>
                <li><button onClick={() => setActiveTab('terms')} className="text-slate-500 hover:text-green-600 text-sm transition-colors">{t.nav.terms}</button></li>
              </ul>
            </div>
          </div>
          <div className="pt-8 border-t border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
            <p className="text-slate-400 text-xs">
              &copy; {new Date().getFullYear()} YTThumbs.fun - {t.footer.disclaimer}
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
};

const FaqItem: React.FC<{ question: string; answer: string }> = ({ question, answer }) => {
  const [isOpen, setIsOpen] = useState(false);
  return (
    <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden transition-all shadow-sm">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-8 py-6 flex items-center justify-between hover:bg-slate-50 transition-colors text-left rtl:text-right"
      >
        <span className="font-bold text-slate-800">{question}</span>
        <svg 
          xmlns="http://www.w3.org/2000/svg" 
          className={`h-5 w-5 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} 
          fill="none" viewBox="0 0 24 24" stroke="currentColor"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>
      <div className={`transition-all duration-300 ${isOpen ? 'max-h-[500px] opacity-100' : 'max-h-0 opacity-0 overflow-hidden'}`}>
        <div className="px-8 pb-6 text-slate-600 leading-relaxed text-left rtl:text-right">
          {answer}
        </div>
      </div>
    </div>
  );
};

export default App;
